function solve(nums, edges) {
    const N = nums.length;

    // Step 1: Build Adjacency Matrix
    const adj = Array(N).fill(0).map(() => Array(N).fill(false));

    for (const [u, v] of edges) {
        adj[u][v] = true;
        adj[v][u] = true;
    }

    let count = 0;
    const maxMask = 1 << N;

    // Iterate over all non-empty subsets (masks M from 1 to 2^N - 1)
    for (let M = 1; M < maxMask; M++) {

        // --- 1. Check Parity and Calculate Subset Size ---
        let paritySum = 0;
        let nodeCount = 0;

        for (let i = 0; i < N; i++) {
            if ((M >> i) & 1) {
                nodeCount++;
                // Calculate parity of the sum of nums[i]
                paritySum = (paritySum + nums[i]) % 2;
            }
        }

        if (paritySum !== 0) {
            continue; // Sum is odd, skip
        }

        // --- 2. Check Connectivity using BFS ---

        // Find the starting node (must exist since M >= 1)
        let startNode = -1;
        for (let i = 0; i < N; i++) {
            if ((M >> i) & 1) {
                startNode = i;
                break;
            }
        }

        // BFS initialization
        const queue = [startNode];
        // visited tracks nodes belonging to S that have been reached
        const visited = new Array(N).fill(false);
        visited[startNode] = true;
        let visitedCount = 1;

        let head = 0;
        while (head < queue.length) {
            const u = queue[head++];

            for (let v = 0; v < N; v++) {
                // Check conditions for moving from u to v:
                // 1. v must be in the subset S ((M >> v) & 1)
                // 2. u and v must be adjacent (adj[u][v])
                // 3. v must not have been visited yet (!visited[v])
                if (((M >> v) & 1) && adj[u][v] && !visited[v]) {
                    visited[v] = true;
                    visitedCount++;
                    queue.push(v);
                }
            }
        }

        // If the number of visited nodes equals the total size of the subset S, it is connected.
        if (visitedCount === nodeCount) {
            count++;
        }
    }

    return count;
}

