func solve(nums []int64, edges [][]int64) int64 {
	N := len(nums)

	// Step 1: Build Adjacency Matrix
	// adj[i][j] is true if there is an edge between i and j
	adj := make([][]bool, N)
	for i := range adj {
		adj[i] = make([]bool, N)
	}

	for _, edge := range edges {
		u := int(edge[0])
		v := int(edge[1])
		adj[u][v] = true
		adj[v][u] = true
	}

	var count int64 = 0
	maxMask := 1 << N

	// Iterate over all non-empty subsets (masks M from 1 to 2^N - 1)
	for M := 1; M < maxMask; M++ {

		// --- 1. Check Parity and Calculate Subset Size ---
		var paritySum int64 = 0
		nodeCount := 0

		for i := 0; i < N; i++ {
			if (M>>i)&1 == 1 {
				nodeCount++
				// Calculate parity of the sum of nums[i]
